import{_ as e,o as t,c as s,O as r}from"./chunks/framework.0d5b6918.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/guide/index.md","filePath":"en/guide/index.md","lastUpdated":1776439080000}'),n={name:"en/guide/index.md"};function i(l,a,p,d,c,o){return t(),s("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Start Here</p><h1>Start Here</h1><div class="brand-hero__panel"><span class="brand-pill">Guide First</span><strong>On a first visit, the biggest time sink is usually not missing features. It is not knowing which path to start with.</strong><p>This page separates the entry points, user roles, and reading path before you go deeper.</p></div><p class="brand-lead"> This guide helps first-time ExecFabric visitors decide whether they should <strong>start with the free path, expand personal local script slots, move into the standard team edition, or go straight into an enterprise delivery conversation.</strong></p><div class="brand-chip-list"><span class="brand-chip">Try first</span><span class="brand-chip">Local script slots</span><span class="brand-chip">Standard team edition</span><span class="brand-chip">CLI bridge</span><span class="brand-chip">Enterprise delivery</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="https://execfabric.cn/">Open Getting Started</a><a class="cta-button" href="./faq.html">Open FAQ</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // START HERE</span><span>GUIDE 01</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">firstVisit</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;free_entry&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;login&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;core_docs&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">localPath</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;local_scripts&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;cli_bridge&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;manifest&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;run&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">deliveryPath</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;tenant_delivery&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;delivery_docs&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;hot_update&#39;</span><span class="matrix-panel__punct">]</span></span></div><div class="matrix-panel__callout">PICK THE PATH THAT MATCHES YOUR STAGE</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">entry</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">public</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">docs</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">mapped</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">route</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">guided</span></span></div></div></div></section><section class="brand-grid brand-grid--four"><article class="brand-card"><p class="brand-kicker">Path A</p><h2>Start with the free path</h2><p>If you are still deciding whether this platform is the right fit, start with the public experience path before deciding whether to register, log in, or discuss a real scenario.</p></article><article class="brand-card"><p class="brand-kicker">Path B</p><h2>Personal continuation / local script slots</h2><p>If you are already connecting scripts in your personal space but have not moved into multi-user collaboration yet, review local script-slot expansion and CLI boundaries before switching to enterprise-delivery language.</p></article><article class="brand-card"><p class="brand-kicker">Path C</p><h2>You need the standard team edition</h2><p>If your focus is multi-user collaboration, formal tenants, and a stable usage cycle, start with billing, membership, customer flow, and the shared-SaaS boundary.</p></article><article class="brand-card"><p class="brand-kicker">Path D</p><h2>You need enterprise delivery</h2><p>If you are here with a client project, intranet constraints, private deployment, or formal acceptance requirements, focus on customer flow, deployment, and delivery boundaries rather than free-entry details.</p></article></section><section class="brand-card"><p class="brand-kicker">Public Entry</p><h2>Current public entry points that are officially available</h2><table><thead><tr><th>Entry type</th><th>How to understand it today</th><th>Best for</th><th>What to read next</th></tr></thead><tbody><tr><td>Public experience flow</td><td>You can now enter from <code>/experience</code>, <code>/login</code>, and <code>/register</code> directly for the experience and signup flow</td><td>People touching the platform for the first time</td><td><a href="https://execfabric.cn/">Getting Started</a></td></tr><tr><td>Product &amp; Delivery Docs</td><td>Explains what the platform is, how delivery works, how deployment works, and how it evolves</td><td>Product, presales, and technical leads</td><td><a href="../product/index.html">Product Overview</a></td></tr><tr><td>CLI &amp; Local Agent Docs</td><td>Explains the current boundary of local login, capability registration, execution, and the Agent skeleton</td><td>Developers and local-bridge scenarios</td><td><a href="../product/cli.html">CLI &amp; Local Agent Guide</a></td></tr><tr><td>Customer Delivery &amp; Usage Docs</td><td>Explains how customers use the platform, how delivery works, and how script hot updates are handled</td><td>Delivery owners and project owners</td><td><a href="../product/customer-flow.html">Customer Delivery &amp; Usage</a></td></tr><tr><td>Contact entry</td><td>Used for four-way routing: the free path, local script slots, the standard team edition, and enterprise delivery</td><td>People who want to move forward</td><td><a href="/en/contact.html#lead-form">Lead routing</a></td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Role Based</p><h2>Where different roles should start</h2><div class="brand-grid brand-grid--four"><article class="brand-card brand-card--nested"><h3>Individual developers</h3><p>Start with Getting Started, then the CLI &amp; Local Agent Guide, then decide whether you need a deeper team or enterprise path.</p></article><article class="brand-card brand-card--nested"><h3>Small-team owners</h3><p>Start with Product Overview, Billing &amp; Membership, and Customer Delivery &amp; Usage, then decide whether the standard team edition is enough or whether you need to move up into enterprise delivery.</p></article><article class="brand-card brand-card--nested"><h3>Presales / solution roles</h3><p>Start with the materials, then return to Product Overview, Deployment &amp; Delivery Boundaries, and Customer Delivery &amp; Usage to establish a consistent narrative.</p></article><article class="brand-card brand-card--nested"><h3>Enterprise customers</h3><p>Start with Customer Delivery &amp; Usage and Deployment &amp; Delivery Boundaries, then confirm tenant isolation, hot-update boundaries, and the follow-up collaboration model.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Reading Order</p><h2>Enter by goal</h2><div class="brand-link-grid"><a class="brand-link-card" href="https://execfabric.cn/"><span>Step 01</span><strong>Getting Started</strong><p>First confirm the public entry points, experience path, and current capability boundary.</p></a><a class="brand-link-card" href="../product/index.html"><span>Step 02</span><strong>Product Overview</strong><p>Then understand what the platform is, which scenarios it fits, and which capabilities are already available.</p></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Step 03</span><strong>Customer Delivery &amp; Usage</strong><p>See how customers use it, how delivery works, and how script hot updates are currently closed-looped.</p></a><a class="brand-link-card" href="../product/onboarding-checklist.html"><span>Step 04</span><strong>Onboarding Checklist</strong><p>When preparing a real project, use this to align the script directory, README, example files, and boundary information in one pass.</p></a><a class="brand-link-card" href="../product/file-results.html"><span>Step 05</span><strong>Files &amp; Results</strong><p>If the task depends on input files, output files, or report artifacts, this page is more practical than a generic product description.</p></a><a class="brand-link-card" href="../product/cli.html"><span>Step 06</span><strong>CLI &amp; Local Agent Guide</strong><p>If you already have a local script directory, this page is more useful than a broad introduction.</p></a><a class="brand-link-card" href="./faq.html"><span>Step 07</span><strong>FAQ</strong><p>Use it to settle questions such as whether this is just a chat product, whether tenants can leak into one another, or whether it can be used for real delivery now.</p></a><a class="brand-link-card" href="../materials/index.html"><span>Step 08</span><strong>Materials</strong><p>If you need presentation, scenario, or solution-communication assets, continue from there.</p></a></div></section><section class="brand-card"><p class="brand-kicker">Project Ready</p><h2>Common materials for real projects</h2><div class="brand-link-grid brand-link-grid--three"><a class="brand-link-card" href="../product/deliverables.html"><span>Customer Delivery Docs &amp; Entry Points</span><strong>Customer Delivery Docs &amp; Entry Points</strong><p>Clarify what entry points, instructions, and result artifacts the customer will finally receive before the delivery phase gets messy.</p></a><a class="brand-link-card" href="../product/onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong><p>Useful for presales, implementation, and the customer to align script directories, README files, examples, dependencies, and risk boundaries together.</p></a><a class="brand-link-card" href="../product/file-results.html"><span>Files</span><strong>Files &amp; Results</strong><p>If the project is file-driven, report-driven, or artifact-driven, this page should be reviewed before rollout rather than patched in afterward.</p></a></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>If you want to move forward, choose the next page by goal</h2><p class="brand-lead">The free path, local script slots, the standard team edition, and enterprise delivery all exist, but they should not be mixed together.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="https://execfabric.cn/"><span>Guide</span><strong>Getting Started</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>Customer Delivery &amp; Usage</strong></a><a class="brand-link-card" href="../product/onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong></a><a class="brand-link-card" href="../product/cli.html"><span>CLI</span><strong>CLI &amp; Local Agent Guide</strong></a><a class="brand-link-card" href="/en/contact.html#lead-form"><span>Lead</span><strong>Lead Routing</strong></a></div></div></section></div>',1)]))}const u=e(n,[["render",i]]);export{m as __pageData,u as default};
